// Bicep: abbreviation registry module (abbr.bicep)
// Store all organization-approved abbreviations in one place.
// Modules import this to build names without hardcoding prefixes.
,

// abbr.bicep — output only, no parameters, no resources
output abbr object = {
  // Compute
  virtualMachine:             'vm'
  virtualMachineScaleSet:     'vmss'
  availabilitySet:            'avail'
  aksCluster:                 'aks'
  functionApp:                'func'
  appServiceApp:              'app'
  appServicePlan:             'plan'
  containerInstance:          'aci'
  containerApp:               'ca'

  // Networking
  virtualNetwork:             'vnet'
  subnet:                     'snet'
  networkSecurityGroup:       'nsg'
  publicIpAddress:            'pip'
  loadBalancer:               'lb'
  applicationGateway:         'agw'
  azureFirewall:              'afw'
  bastionHost:                'bas'
  privateEndpoint:            'pe'
  privateDnsZone:             'pdns'
  expressRouteCircuit:        'erc'
  vpnGateway:                 'vpng'
  routeTable:                 'rt'

  // Storage
  storageAccount:             'st'     // no separator: st{workload}{env}{region}
  managedDisk:                'disk'
  recoveryServicesVault:      'rsv'
  dataLakeStore:              'dls'

  // Databases
  sqlServer:                  'sql'
  sqlDatabase:                'sqldb'
  cosmosDb:                   'cosmos'
  redisCache:                 'redis'
  postgreSqlServer:           'psql'
  mySqlServer:                'mysql'

  // Security
  keyVault:                   'kv'
  managedIdentityUser:        'id'
  containerRegistry:          'acr'   // no separator: acr{workload}{env}{region}

  // Integration
  apiManagement:              'apim'
  logicApp:                   'logic'
  serviceBusNamespace:        'sbns'
  eventHubNamespace:          'evhns'
  eventGridTopic:             'evgt'

  // Management & monitoring
  logAnalyticsWorkspace:      'log'
  appInsights:                'appi'
  automationAccount:          'aa'
  resourceGroup:              'rg'
}

// Usage in main.bicep:
// module abbr 'abbr.bicep' = { name: 'abbr' }
// var a = abbr.outputs.abbr
// resource kv 'Microsoft.KeyVault/vaults@2023-07-01' = {
//   name: '${a.keyVault}-payments-prod-eus'
// }

# Azure Policy: enforce abbreviation prefix using match conditions
# The match condition uses wildcards: ? = any char, * = any chars, # = any digit

# 1. Deny VMs not starting with 'vm-'
az policy definition create \
  --name 'require-vm-prefix' \
  --display-name 'Require vm- prefix on Virtual Machines' \
  --mode All \
  --rules '{
    "if": {
      "allOf": [
        {"field": "type", "equals": "Microsoft.Compute/virtualMachines"},
        {"not": {"field": "name", "match": "vm-*"}}
      ]
    },
    "then": {"effect": "Deny"}
  }' \
  --management-group mg-corp

# 2. Deny VNets not starting with 'vnet-'
az policy definition create \
  --name 'require-vnet-prefix' \
  --display-name 'Require vnet- prefix on Virtual Networks' \
  --mode All \
  --rules '{
    "if": {
      "allOf": [
        {"field": "type", "equals": "Microsoft.Network/virtualNetworks"},
        {"not": {"field": "name", "match": "vnet-*"}}
      ]
    },
    "then": {"effect": "Deny"}
  }' \
  --management-group mg-corp

# 3. Deny Key Vaults not starting with 'kv-'
az policy definition create \
  --name 'require-kv-prefix' \
  --display-name 'Require kv- prefix on Key Vaults' \
  --mode All \
  --rules '{
    "if": {
      "allOf": [
        {"field": "type", "equals": "Microsoft.KeyVault/vaults"},
        {"not": {"field": "name", "match": "kv-*"}}
      ]
    },
    "then": {"effect": "Deny"}
  }' \
  --management-group mg-corp

# 4. Deny Storage Accounts not starting with 'st'
az policy definition create \
  --name 'require-sa-prefix' \
  --display-name 'Require st prefix on Storage Accounts' \
  --mode All \
  --rules '{
    "if": {
      "allOf": [
        {"field": "type", "equals": "Microsoft.Storage/storageAccounts"},
        {"not": {"field": "name", "match": "st*"}}
      ]
    },
    "then": {"effect": "Audit"}
  }' \
  --management-group mg-corp
# Note: Storage accounts use Audit rather than Deny because the prefix check alone
# cannot enforce the full no-hyphen constraint in a single Policy rule.
